import React, { useState } from "react";

function App() {
  const [name, setName] = useState("");

  const handleGenerate = async (e) => {
    e.preventDefault();
    if (!name) {
      alert("Please enter your name");
      return;
    }

    const response = await fetch("http://localhost:5000/generate-certificate", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name }),
    });

    const blob = await response.blob();
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${name}-certificate.pdf`;
    document.body.appendChild(a);
    a.click();
    a.remove();
  };

return (
  <div className="min-h-screen flex items-center justify-center bg-white px-4">
    <div className="text-center">
      <h1 className="text-3xl font-bold mb-2">🎓 Certificate Generator</h1>
      <p className="mb-4">Enter your name below to generate your custom certificate.</p>

      <form onSubmit={handleGenerate} className="flex flex-col items-center">
        <input
          type="text"
          placeholder="Enter your name"
          value={name}
          onChange={(e) => setName(e.target.value)}
          style={{ padding: '10px', width: '100%', maxWidth: '300px' }}
        />
        <br />
        <button
          type="submit"
          style={{ padding: '10px 20px', width: '100%', maxWidth: '300px' }}
        >
          Generate Certificate
        </button>
      </form>
    </div>
  </div>
);

}

export default App;
